// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>

// Structure to represent a citizen
typedef struct {
    int cobol;
    int pole_vault;
    int doughnut_eating;
} Citizen;

// Comparison function for sorting citizens
int compare_citizens(const void *a, const void *b) {
    Citizen *citizen1 = (Citizen *)a;
    Citizen *citizen2 = (Citizen *)b;
    return (citizen1->cobol + citizen1->pole_vault + citizen1->doughnut_eating) - (citizen2->cobol + citizen2->pole_vault + citizen2->doughnut_eating);
}

int main() {
    int N;
    scanf("%d", &N);
    Citizen citizens[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d %d", &citizens[i].cobol, &citizens[i].pole_vault, &citizens[i].doughnut_eating);
    }
    qsort(citizens, N, sizeof(Citizen), compare_citizens);
    int max_time = 0;
    int current_time = 0;
    for (int i = 0; i < N; i++) {
        current_time += citizens[i].cobol;
        max_time = (max_time > current_time) ? max_time : current_time;
        current_time += citizens[i].pole_vault + citizens[i].doughnut_eating;
    }
    printf("%d\n", max_time);
    return 0;
}

