// COMPLETE, COMPILABLE Java code
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static class Citizen implements Comparable<Citizen> {
        int cobol;
        int pole_vault;
        int doughnut_eating;
        Citizen(int cobol, int pole_vault, int doughnut_eating) {
            this.cobol = cobol;
            this.pole_vault = pole_vault;
            this.doughnut_eating = doughnut_eating;
        }
        @Override
        public int compareTo(Citizen other) {
            return (this.cobol + this.pole_vault + this.doughnut_eating) - (other.cobol + other.pole_vault + other.doughnut_eating);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Citizen[] citizens = new Citizen[N];
        for (int i = 0; i < N; i++) {
            citizens[i] = new Citizen(scanner.nextInt(), scanner.nextInt(), scanner.nextInt());
        }
        Arrays.sort(citizens);
        int max_time = 0;
        int current_time = 0;
        for (int i = 0; i < N; i++) {
            current_time += citizens[i].cobol;
            max_time = (max_time > current_time) ? max_time : current_time;
            current_time += citizens[i].pole_vault + citizens[i].doughnut_eating;
        }
        System.out.println(max_time);
    }
}

